import os
import pty
import select
import signal
import struct
import termios
import fcntl
import time

import pyte

from base_terminal import BaseTerminal


class HeadlessTerminal(BaseTerminal):
    """A headless terminal emulator backed by a real PTY running an
    interactive bash shell.

    Keystrokes (including control characters such as ``"\\x03"`` for Ctrl-C)
    are written to the PTY master. Output produced by the shell and any
    interactive programs is fed through a :mod:`pyte` screen so the current
    visible terminal state can be inspected via :meth:`get_screen`.
    """

    def __init__(
        self,
        rows: int = 24,
        cols: int = 80,
        cwd: str | None = None,
        env: dict | None = None,
    ) -> None:
        self.rows = rows
        self.cols = cols

        # pyte screen + stream to interpret terminal output.
        self.screen = pyte.Screen(cols, rows)
        self.stream = pyte.ByteStream(self.screen)

        # Build the child environment.
        child_env = os.environ.copy()
        if env:
            child_env.update(env)
        child_env["TERM"] = child_env.get("TERM", "linux")
        # Avoid line wrapping surprises / pagers blocking on input.
        child_env["COLUMNS"] = str(cols)
        child_env["LINES"] = str(rows)

        # Fork a child attached to a new PTY.
        pid, master_fd = pty.fork()
        if pid == 0:
            # Child process.
            try:
                if cwd:
                    os.chdir(cwd)
            except Exception:
                pass
            # Interactive login shell so startup files (~/.bashrc etc.) are
            # sourced. ``-i`` forces interactivity, ``-l`` acts as a login
            # shell.
            shell = child_env.get("SHELL", "/bin/bash")
            try:
                os.execvpe(shell, [shell, "-i", "-l"], child_env)
            except Exception:
                os.execvpe("/bin/sh", ["/bin/sh", "-i"], child_env)
            os._exit(1)

        # Parent process.
        self.pid = pid
        self.master_fd = master_fd
        self._set_winsize(rows, cols)

        # Drain the initial shell startup output (prompt, banners).
        self._read_until_idle()

    # -- internal helpers ------------------------------------------------

    def _set_winsize(self, rows: int, cols: int) -> None:
        try:
            winsize = struct.pack("HHHH", rows, cols, 0, 0)
            fcntl.ioctl(self.master_fd, termios.TIOCSWINSZ, winsize)
        except Exception:
            pass

    def _read_until_idle(
        self, idle_time: float = 0.2, max_time: float = 10.0
    ) -> None:
        """Read available output, feeding it to the pyte screen, until no
        new data arrives for ``idle_time`` seconds (or ``max_time`` elapses).
        """
        deadline = time.time() + max_time
        last_data = time.time()
        while True:
            timeout = idle_time
            try:
                rlist, _, _ = select.select([self.master_fd], [], [], timeout)
            except (OSError, ValueError):
                break
            if rlist:
                try:
                    data = os.read(self.master_fd, 65536)
                except OSError:
                    break
                if not data:
                    break
                self.stream.feed(data)
                last_data = time.time()
            else:
                # No data within idle window -> considered idle.
                if time.time() - last_data >= idle_time:
                    break
            if time.time() > deadline:
                break

    # -- public API ------------------------------------------------------

    def send_keystrokes(self, keystrokes: str, wait_sec: float = 0.0) -> None:
        """Send ``keystrokes`` to the terminal.

        Characters are written verbatim to the PTY, so control sequences such
        as ``"\\x03"`` (Ctrl-C) or ``"\\n"`` (Enter) work as expected. After
        writing, output is drained (waiting at least ``wait_sec`` seconds) and
        applied to the emulated screen.
        """
        data = keystrokes.encode("utf-8", errors="surrogateescape")
        # Write all bytes, handling partial writes.
        while data:
            try:
                n = os.write(self.master_fd, data)
            except OSError:
                break
            data = data[n:]

        if wait_sec and wait_sec > 0:
            end = time.time() + wait_sec
            while time.time() < end:
                remaining = end - time.time()
                try:
                    rlist, _, _ = select.select(
                        [self.master_fd], [], [], remaining
                    )
                except (OSError, ValueError):
                    break
                if rlist:
                    try:
                        chunk = os.read(self.master_fd, 65536)
                    except OSError:
                        break
                    if chunk:
                        self.stream.feed(chunk)

        # Drain whatever is left until the terminal is idle.
        self._read_until_idle()

    def get_screen(self) -> str:
        """Return the current visible screen contents as a string."""
        lines = [line.rstrip() for line in self.screen.display]
        return "\n".join(lines).rstrip("\n")

    # Convenient aliases commonly used by terminal harnesses.
    def capture(self) -> str:
        return self.get_screen()

    def read_screen(self) -> str:
        return self.get_screen()

    def close(self) -> None:
        """Terminate the child shell and release resources."""
        try:
            os.close(self.master_fd)
        except OSError:
            pass
        if getattr(self, "pid", None):
            try:
                os.kill(self.pid, signal.SIGKILL)
            except OSError:
                pass
            try:
                os.waitpid(self.pid, 0)
            except OSError:
                pass
            self.pid = None

    def __del__(self):
        try:
            self.close()
        except Exception:
            pass
